## Task Description

Define the core types for the circuit breaker pattern: the CircuitState enum representing the three states, and CircuitBreakerConfig for tuning behavior.

## Design

### CircuitState Enum
```rust
// In rchd/src/health.rs or new rchd/src/circuit.rs

use std::time::{Duration, Instant};
use serde::{Deserialize, Serialize};

/// Circuit breaker state for a worker
#[derive(Debug, Clone)]
pub enum CircuitState {
    /// Circuit closed - worker is healthy and accepting requests
    /// This is the normal operating state.
    Closed,

    /// Circuit open - worker has failed too many times
    /// Worker is excluded from selection until cooldown expires.
    Open {
        /// When the circuit was tripped
        tripped_at: Instant,
        /// How many times this circuit has been tripped (for backoff calculation)
        trip_count: u32,
        /// When to attempt the next probe
        next_probe_at: Instant,
    },

    /// Circuit half-open - testing if worker has recovered
    /// A single probe request is allowed through.
    HalfOpen {
        /// When we entered half-open state
        entered_at: Instant,
    },
}

impl Default for CircuitState {
    fn default() -> Self {
        CircuitState::Closed
    }
}

impl CircuitState {
    /// Check if the circuit allows requests through
    pub fn is_closed(&self) -> bool {
        matches!(self, CircuitState::Closed)
    }

    /// Check if the circuit is open (blocking requests)
    pub fn is_open(&self) -> bool {
        matches!(self, CircuitState::Open { .. })
    }

    /// Check if we should probe (half-open or cooldown expired)
    pub fn should_probe(&self) -> bool {
        match self {
            CircuitState::Closed => false,
            CircuitState::Open { next_probe_at, .. } => Instant::now() >= *next_probe_at,
            CircuitState::HalfOpen { .. } => true,
        }
    }
}
```

### CircuitBreakerConfig
```rust
/// Configuration for circuit breaker behavior
#[derive(Debug, Clone)]
pub struct CircuitBreakerConfig {
    /// Number of consecutive failures before tripping the circuit
    /// Default: 3
    pub failure_threshold: u32,

    /// Initial cooldown duration before first probe attempt
    /// Default: 30 seconds
    pub initial_cooldown: Duration,

    /// Maximum cooldown duration (caps exponential backoff)
    /// Default: 5 minutes
    pub max_cooldown: Duration,

    /// Multiplier for exponential backoff
    /// Each trip: cooldown = min(initial * multiplier^trip_count, max)
    /// Default: 2.0
    pub backoff_multiplier: f64,

    /// Number of successful probes needed to close circuit
    /// Default: 1
    pub success_threshold: u32,
}

impl Default for CircuitBreakerConfig {
    fn default() -> Self {
        Self {
            failure_threshold: 3,
            initial_cooldown: Duration::from_secs(30),
            max_cooldown: Duration::from_secs(300), // 5 minutes
            backoff_multiplier: 2.0,
            success_threshold: 1,
        }
    }
}

impl CircuitBreakerConfig {
    /// Calculate cooldown duration for given trip count
    pub fn cooldown_for_trip(&self, trip_count: u32) -> Duration {
        let multiplier = self.backoff_multiplier.powi(trip_count as i32);
        let cooldown_secs = self.initial_cooldown.as_secs_f64() * multiplier;
        let capped = cooldown_secs.min(self.max_cooldown.as_secs_f64());
        Duration::from_secs_f64(capped)
    }
}
```

### Serializable Status (for API)
```rust
/// Serializable circuit state for status API
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CircuitStateInfo {
    pub state: String,  // "closed", "open", "half_open"
    pub trip_count: Option<u32>,
    pub next_probe_in_secs: Option<u64>,
}

impl From<&CircuitState> for CircuitStateInfo {
    fn from(state: &CircuitState) -> Self {
        match state {
            CircuitState::Closed => CircuitStateInfo {
                state: "closed".to_string(),
                trip_count: None,
                next_probe_in_secs: None,
            },
            CircuitState::Open { trip_count, next_probe_at, .. } => {
                let secs_until = next_probe_at
                    .saturating_duration_since(Instant::now())
                    .as_secs();
                CircuitStateInfo {
                    state: "open".to_string(),
                    trip_count: Some(*trip_count),
                    next_probe_in_secs: Some(secs_until),
                }
            },
            CircuitState::HalfOpen { .. } => CircuitStateInfo {
                state: "half_open".to_string(),
                trip_count: None,
                next_probe_in_secs: None,
            },
        }
    }
}
```

